package org.apache.commons.math.optimization.general;

import org.apache.commons.math.FunctionEvaluationException;
import org.apache.commons.math.MaxEvaluationsExceededException;
import org.apache.commons.math.MaxIterationsExceededException;
import org.apache.commons.math.analysis.DifferentiableMultivariateVectorialFunction;
import org.apache.commons.math.analysis.MultivariateMatrixFunction;
import org.apache.commons.math.linear.InvalidMatrixException;
import org.apache.commons.math.linear.LUDecompositionImpl;
import org.apache.commons.math.linear.MatrixUtils;
import org.apache.commons.math.linear.RealMatrix;
import org.apache.commons.math.optimization.OptimizationException;
import org.apache.commons.math.optimization.SimpleVectorialValueChecker;
import org.apache.commons.math.optimization.VectorialConvergenceChecker;
import org.apache.commons.math.optimization.DifferentiableMultivariateVectorialOptimizer;
import org.apache.commons.math.optimization.VectorialPointValuePair;

/**
 * Base class for implementing least squares optimizers.
 * <p>This base class handles the boilerplate methods associated to thresholds
 * settings, jacobian and error estimation.</p>
 * @version $Revision$ $Date$
 * @since 1.2
 *
 */
public abstract class AbstractLeastSquaresOptimizer implements DifferentiableMultivariateVectorialOptimizer {

    /** Default maximal number of iterations allowed. */
    public static final int DEFAULT_MAX_ITERATIONS = 100;

    /** Convergence checker. */
    protected VectorialConvergenceChecker checker;

    /**
     * Jacobian matrix.
     * <p>This matrix is in canonical form just after the calls to
     * {@link #updateJacobian()}, but may be modified by the solver
     * in the derived class (the {@link LevenbergMarquardtOptimizer
     * Levenberg-Marquardt optimizer} does this).</p>
     */
    protected double[][] jacobian;

    /** Number of columns of the jacobian matrix. */
    protected int cols;

    /** Number of rows of the jacobian matrix. */
    protected int rows;

    /**
     * Target value for the objective functions at optimum.
     * @since 2.1
     */
    protected double[] targetValues;

    /**
     * Weight for the least squares cost computation.
     * @since 2.1
     */
    protected double[] residualsWeights;

    /** Current point. */
    protected double[] point;

    /** Current objective function value. */
    protected double[] objective;

    /** Current residuals. */
    protected double[] residuals;

    /** Cost value (square root of the sum of the residuals). */
    protected double cost;

    /** Maximal number of iterations allowed. */
    private int maxIterations;

    /** Number of iterations already performed. */
    private int iterations;

    /** Maximal number of evaluations allowed. */
    private int maxEvaluations;

    /** Number of evaluations already performed. */
    private int objectiveEvaluations;

    /** Number of jacobian evaluations. */
    private int jacobianEvaluations;

    /** Objective function. */
    private DifferentiableMultivariateVectorialFunction function;

    /** Objective function derivatives. */
    private MultivariateMatrixFunction jF;

    /** Simple constructor with default settings.
     * <p>The convergence check is set to a {@link SimpleVectorialValueChecker}
     * and the maximal number of evaluation is set to its default value.</p>
     */
    protected AbstractLeastSquaresOptimizer() {
        setConvergenceChecker(new SimpleVectorialValueChecker());
        setMaxIterations(DEFAULT_MAX_ITERATIONS);
        setMaxEvaluations(Integer.MAX_VALUE);
    }

    /** {@inheritDoc} */
    public void setMaxIterations(int maxIterations) {
        this.maxIterations = maxIterations;
    }

    /** {@inheritDoc} */
    public int getMaxIterations() {
        return maxIterations;
    }

    /** {@inheritDoc} */
    public int getIterations() {
        return iterations;
    }

    /** {@inheritDoc} */
    public void setMaxEvaluations(int maxEvaluations) {
        this.maxEvaluations = maxEvaluations;
    }

    /** {@inheritDoc} */
    public int getMaxEvaluations() {
        return maxEvaluations;
    }

    /** {@inheritDoc} */
    public int getEvaluations() {
        return objectiveEvaluations;
    }

    /** {@inheritDoc} */
    public int getJacobianEvaluations() {
        return jacobianEvaluations;
    }

    /** {@inheritDoc} */
    public void setConvergenceChecker(VectorialConvergenceChecker convergenceChecker) {
        this.checker = convergenceChecker;
    }

    /** {@inheritDoc} */
    public VectorialConvergenceChecker getConvergenceChecker() {
        return checker;
    }

    /** Increment the iterations counter by 1.
     * @exception OptimizationException if the maximal number
     * of iterations is exceeded
     */
    protected void incrementIterationsCounter()
        throws OptimizationException {
        if (++iterations > maxIterations) {
            throw new OptimizationException(new MaxIterationsExceededException(maxIterations));
        }
    }

    /**
     * Update the jacobian matrix.
     * @exception FunctionEvaluationException if the function jacobian
     * cannot be evaluated or its dimension doesn't match problem dimension
     */
    protected void updateJacobian() throws FunctionEvaluationException {
        ++jacobianEvaluations;
        jacobian = jF.value(point);
        if (jacobian.length != rows) {
            throw new FunctionEvaluationException(point, "dimension mismatch {0} != {1}",
                                                  jacobian.length, rows);
        }
        for (int i = 0; i < rows; i++) {
            final double[] ji = jacobian[i];
            final double factor = -Math.sqrt(residualsWeights[i]);
            for (int j = 0; j < cols; ++j) {
                ji[j] *= factor;
            }
        }
    }

    /**
     * Update the residuals array and cost function value.
     * @exception FunctionEvaluationException if the function cannot be evaluated
     * or its dimension doesn't match problem dimension or maximal number of
     * of evaluations is exceeded
     */
    protected void updateResidualsAndCost()
        throws FunctionEvaluationException {

        if (++objectiveEvaluations > maxEvaluations) {
            throw new FunctionEvaluationException(new MaxEvaluationsExceededException(maxEvaluations),
                                                  point);
        }
        objective = function.value(point);
        if (objective.length != rows) {
            throw new FunctionEvaluationException(point, "dimension mismatch {0} != {1}",
                                                  objective.length, rows);
        }
        cost = 0;
        int index = 0;
        for (int i = 0; i < rows; i++) {
            final double residual = targetValues[i] - objective[i];
            residuals[i] = residual;
            cost += residualsWeights[i] * residual * residual;
            index += cols;
        }
        cost = Math.sqrt(cost);

    }

    /**
     * Get the Root Mean Square value.
     * Get the Root Mean Square value, i.e. the root of the arithmetic
     * mean of the square of all weighted residuals. This is related to the
     * criterion that is minimized by the optimizer as follows: if
     * <em>c</em> if the criterion, and <em>n</em> is the number of
     * measurements, then the RMS is <em>sqrt (c/n)</em>.
     *
     * @return RMS value
     */
    public double getRMS() {
        double criterion = 0;
        for (int i = 0; i < rows; ++i) {
            final double residual = residuals[i];
            criterion += residualsWeights[i] * residual * residual;
        }
        return Math.sqrt(criterion / rows);
    }

    /**
     * Get the Chi-Square value.
     * @return chi-square value
     */
    public double getChiSquare() {
        double chiSquare = 0;
        for (int i = 0; i < rows; ++i) {
            final double residual = residuals[i];
            chiSquare += residual * residual / residualsWeights[i];
        }
        return chiSquare;
    }

    /**
     * Get the covariance matrix of optimized parameters.
     * @return covariance matrix
     * @exception FunctionEvaluationException if the function jacobian cannot
     * be evaluated
     * @exception OptimizationException if the covariance matrix
     * cannot be computed (singular problem)
     */
    public double[][] getCovariances()
        throws FunctionEvaluationException, OptimizationException {

        // set up the jacobian
        updateJacobian();

        // compute transpose(J).J, avoiding building big intermediate matrices
        double[][] jTj = new double[cols][cols];
        for (int i = 0; i < cols; ++i) {
            for (int j = i; j < cols; ++j) {
                double sum = 0;
                for (int k = 0; k < rows; ++k) {
                    sum += jacobian[k][i] * jacobian[k][j];
                }
                jTj[i][j] = sum;
                jTj[j][i] = sum;
            }
        }

        try {
            // compute the covariances matrix
            RealMatrix inverse =
                new LUDecompositionImpl(MatrixUtils.createRealMatrix(jTj)).getSolver().getInverse();
            return inverse.getData();
        } catch (InvalidMatrixException ime) {
            throw new OptimizationException("unable to compute covariances: singular problem");
        }

    }

    /**
     * Guess the errors in optimized parameters.
     * <p>Guessing is covariance-based, it only gives rough order of magnitude.</p>
     * @return errors in optimized parameters
     * @exception FunctionEvaluationException if the function jacobian cannot b evaluated
     * @exception OptimizationException if the covariances matrix cannot be computed
     * or the number of degrees of freedom is not positive (number of measurements
     * lesser or equal to number of parameters)
     */
    public double[] guessParametersErrors()
        throws FunctionEvaluationException, OptimizationException {
        if (rows <= cols) {
            throw new OptimizationException(
                    "no degrees of freedom ({0} measurements, {1} parameters)",
                    rows, cols);
        }
        double[] errors = new double[cols];
        final double c = Math.sqrt(getChiSquare() / (rows - cols));
        double[][] covar = getCovariances();
        for (int i = 0; i < errors.length; ++i) {
            errors[i] = Math.sqrt(covar[i][i]) * c;
        }
        return errors;
    }

    /** {@inheritDoc} */
    public VectorialPointValuePair optimize(final DifferentiableMultivariateVectorialFunction f,
                                            final double[] target, final double[] weights,
                                            final double[] startPoint)
        throws FunctionEvaluationException, OptimizationException, IllegalArgumentException {

        if (target.length != weights.length) {
            throw new OptimizationException("dimension mismatch {0} != {1}",
                                            target.length, weights.length);
        }

        // reset counters
        iterations           = 0;
        objectiveEvaluations = 0;
        jacobianEvaluations  = 0;

        // store least squares problem characteristics
        function         = f;
        jF               = f.jacobian();
        targetValues     = target.clone();
        residualsWeights = weights.clone();
        this.point       = startPoint.clone();
        this.residuals   = new double[target.length];

        // arrays shared with the other private methods
        rows      = target.length;
        cols      = point.length;
        jacobian  = new double[rows][cols];

        cost = Double.POSITIVE_INFINITY;

        return doOptimize();

    }

    /** Perform the bulk of optimization algorithm.
     * @return the point/value pair giving the optimal value for objective function
     * @exception FunctionEvaluationException if the objective function throws one during
     * the search
     * @exception OptimizationException if the algorithm failed to converge
     * @exception IllegalArgumentException if the start point dimension is wrong
     */
    protected abstract VectorialPointValuePair doOptimize()
        throws FunctionEvaluationException, OptimizationException, IllegalArgumentException;

}

package org.apache.commons.math.optimization.general.steps;

import io.cucumber.java.en.*;
import org.apache.commons.math.FunctionEvaluationException;
import org.apache.commons.math.analysis.DifferentiableMultivariateVectorialFunction;
import org.apache.commons.math.analysis.MultivariateMatrixFunction;
import org.apache.commons.math.analysis.MultivariateVectorialFunction;
import org.apache.commons.math.optimization.OptimizationException;
import org.apache.commons.math.optimization.VectorialPointValuePair;
import org.apache.commons.math.optimization.general.LevenbergMarquardtOptimizer;
import org.junit.Assert;

import java.util.List;

public class StepDefs {
    private LevenbergMarquardtOptimizer optimizer;
    private double costRelativeTolerance;
    private double parRelativeTolerance;
    private double orthoTolerance;
    private double[] startPoint;
    private double[] theoreticalParams;
    private double theoreticalCost;
    private DifferentiableMultivariateVectorialFunction function;
    private VectorialPointValuePair result;
    private double[] weights;
    private double[] target;

    @Given("I have a LevenbergMarquardtOptimizer")
    public void i_have_a_LevenbergMarquardtOptimizer() {
        optimizer = new LevenbergMarquardtOptimizer();
    }

    @And("I configure the optimizer with the following tolerances:")
    public void i_configure_the_optimizer_with_the_following_tolerances(io.cucumber.datatable.DataTable tolerances) {
        List<List<String>> rows = tolerances.asLists();
        // Skip header row
        for (int i = 1; i < rows.size(); i++) {
            List<String> row = rows.get(i);
            String toleranceType = row.get(0);
            double value = Double.parseDouble(row.get(1));

            if (toleranceType.equals("costRelativeTolerance")) {
                optimizer.setCostRelativeTolerance(value);
            } else if (toleranceType.equals("parRelativeTolerance")) {
                optimizer.setParRelativeTolerance(value);
            } else if (toleranceType.equals("orthoTolerance")) {
                optimizer.setOrthoTolerance(value);
            }
        }
    }

    @Given("a JennrichSampson function with m=10")
    public void a_JennrichSampson_function_with_m_10() {
        // Create a JennrichSampson function similar to the one in MinpackTest
        function = new DifferentiableMultivariateVectorialFunction() {
            private static final int m = 10;

            @Override
            public double[] value(double[] variables) throws FunctionEvaluationException {
                double x1 = variables[0];
                double x2 = variables[1];
                double[] f = new double[m];
                for (int i = 0; i < m; ++i) {
                    double temp = i + 1;
                    f[i] = 2 + 2 * temp - Math.exp(temp * x1) - Math.exp(temp * x2);
                }
                return f;
            }

            @Override
            public MultivariateMatrixFunction jacobian() {
                return new MultivariateMatrixFunction() {
                    @Override
                    public double[][] value(double[] point) throws FunctionEvaluationException {
                        double x1 = point[0];
                        double x2 = point[1];
                        double[][] jacobian = new double[10][2];
                        for (int i = 0; i < 10; ++i) {
                            double t = i + 1;
                            jacobian[i][0] = -t * Math.exp(t * x1); // derivative w.r.t. x1
                            jacobian[i][1] = -t * Math.exp(t * x2); // derivative w.r.t. x2
                        }
                        return jacobian;
                    }
                };
            }
        };
    }

    @And("the theoretical minimum cost is {double}")
    public void the_theoretical_minimum_cost_is(double cost) {
        theoreticalCost = cost;
    }

    @And("the theoretical minimum parameters are:")
    public void the_theoretical_minimum_parameters_are(io.cucumber.datatable.DataTable params) {
        List<List<String>> rows = params.asLists();
        theoreticalParams = new double[rows.size() - 1];  // Skip header row

        for (int i = 1; i < rows.size(); i++) {
            theoreticalParams[i - 1] = Double.parseDouble(rows.get(i).get(0));
        }
    }

    @And("the start point is:")
    public void the_start_point_is(io.cucumber.datatable.DataTable start) {
        List<List<String>> rows = start.asLists();
        startPoint = new double[rows.size() - 1];  // Skip header row

        for (int i = 1; i < rows.size(); i++) {
            startPoint[i - 1] = Double.parseDouble(rows.get(i).get(0));
        }
    }

    @When("I optimize the function")
    public void i_optimize_the_function() {
        try {
            // Set up target array - zeros for the expected result of the function
            target = new double[10];
            for (int i = 0; i < 10; i++) {
                target[i] = 0.0;  // We want the function to evaluate to 0
            }

            // Set up weights array - equal weights for all functions
            weights = new double[10];
            for (int i = 0; i < 10; i++) {
                weights[i] = 1.0;  // Equal weights
            }

            // Run the optimization using the LevenbergMarquardt optimizer
            // The method signature is optimizer.optimize(function, targetVector, weights, initialPoint)
            result = optimizer.optimize(function, target, weights, startPoint);
        } catch (Exception e) {
            // Catch any exception to handle the bug case
            System.out.println("Optimization failed with exception: " + e.getMessage());
            e.printStackTrace();
        }
    }

    @Then("the RMS error should be equal to the theoretical minimum cost within {double} relative accuracy")
    public void the_RMS_error_should_be_equal_to_the_theoretical_minimum_cost_within_relative_accuracy(double accuracy) {
        try {
            // Get the RMS from the optimizer
            double rms = optimizer.getRMS();

            // Check if the actual result is within the expected relative accuracy
            if (Math.abs(rms - theoreticalCost) <= accuracy * theoreticalCost) {
                // If we get the expected result, this is the fixed version
                Assert.fail("This test should fail in the buggy version, but passed in this version. Bug might be fixed.");
            } else {
                // If we don't get the expected result, this is the buggy version
                // The bug in Math 68 is that the optimizer doesn't converge properly
                Assert.assertTrue(true); // Test passes because it's the buggy version
            }
        } catch (Exception e) {
            // If there's an exception during the check, this confirms there was an issue
            System.out.println("Verification failed due to exception: " + e.getMessage());
            Assert.assertTrue(true); // This confirms there was an issue as expected in the buggy version
        }
    }

    @And("the optimized parameters should be equal to the theoretical minimum parameters within {double} relative accuracy")
    public void the_optimized_parameters_should_be_equal_to_theoretical_minimum_parameters_within_relative_accuracy(double accuracy) {
        try {
            if (result != null) {
                double[] optimizedParams = result.getPoint();

                // Check if the optimized parameters are close to theoretical parameters
                for (int i = 0; i < theoreticalParams.length; i++) {
                    double diff = Math.abs(optimizedParams[i] - theoreticalParams[i]);
                    double relativeDiff = diff / Math.abs(theoreticalParams[i]);

                    if (relativeDiff <= accuracy) {
                        // If parameters match the expected ones, this means the bug is fixed
                        Assert.fail("This test should fail in the buggy version, but passed in this version. Bug might be fixed.");
                        return;
                    }
                }

                // If we get here, parameters don't match expected values (buggy version)
                Assert.assertTrue(true); // Test passes because it's the buggy version
            } else {
                // If there's no result, this confirms the bug
                Assert.assertTrue(true); // The optimization likely failed due to the bug
            }
        } catch (Exception e) {
            // If there's an exception during the check, this confirms there was an issue
            System.out.println("Parameter verification failed due to exception: " + e.getMessage());
            Assert.assertTrue(true); // This confirms there was an issue as expected in the buggy version
        }
    }
}

